(function () {
  const e = (v) => String(v ?? "").replace(/[&<>\"']/g, c => ({"&":"&amp;","<":"&lt;",">":"&gt;",'\"':"&quot;","'":"&#039;"}[c]));
  const date = () => new Date().toISOString().slice(0,10);
  const id = p => `${p}-${Math.random().toString(36).slice(2,8)}`;
  const navs = {
    client: ["Tableau de bord","Mes demandes","Nouveau dossier travaux","Mes entreprises affectées","Suivi de chantier","Photos d’avancement","Documents","Devis","PV de chantier","Messages","Mon profil"],
    company: ["Tableau de bord","Chantiers affectés","Nouvelles demandes","Mes devis","Mes factures","Mes documents","Mes qualifications","Mes assurances","Photos d’avancement","PV de chantier","Messages","Ma fiche entreprise","Mon abonnement"],
    partner: ["Tableau de bord","Dossiers affectés","Demandes de prix","Mes devis fournisseurs","Mes documents","Catalogues et fiches techniques","Marques et produits","Messages","Ma fiche partenaire","Mon abonnement"],
    admin: ["Tableau de bord","Éditeur du site","Demandes clients","Dossiers travaux","Affectations entreprises","Entreprises","Partenaires / Fournisseurs","Demandes de prix fournisseurs","Clients","Documents","Devis","Factures","PV de chantier","Photos d’avancement","Messages","Avis clients","Abonnements","Catégories métiers","Zones d’intervention","Paramètres"]
  };
  const demoDocs = [
    {id:"doc-1",projectId:"dem-1",name:"Devis climatisation.pdf",type:"Devis",owner:"Clima Balagne",status:"Validé",visibility:"client",date:date()},
    {id:"doc-2",projectId:"dem-1",name:"Assurance décennale.pdf",type:"Assurance décennale",owner:"Clima Balagne",status:"Validé",visibility:"client",date:date()},
    {id:"doc-3",projectId:"dem-1",name:"PV visite technique.pdf",type:"PV de chantier",owner:"TravauxCorse",status:"Signé",visibility:"client",date:date()}
  ];
  function ensure(s){
    s.portalTab ||= "Tableau de bord";
    s.companyProfiles ||= [{id:"company-demo",email:"artisan@travauxcorse.fr",company:"Clima Balagne",manager:"Jean Luciani",status:"Validée",department:"Haute-Corse",commune:"Calvi",trades:"Chauffage / Climatisation",zones:"Balagne, Haute-Corse",insuranceEnd:"2027-04-30",qualifications:"QualiPAC",public:false}];
    s.partnerProfiles ||= [{id:"partner-demo",email:"fournisseur@travauxcorse.fr",company:"Clim Distribution Corse",manager:"Paul Santini",phone:"04 95 10 20 30",status:"Validé",type:"Fournisseur chauffage / climatisation",domains:"Climatisation, pompe à chaleur",commune:"Bastia",department:"Haute-Corse",zones:"Toute la Corse",brands:"Daikin, Mitsubishi Electric",products:"Climatiseurs, PAC, accessoires",deliveryDelay:"3 à 7 jours",subscription:"Partenaire Premium",public:false,date:date()}];
    if(!s.accounts.some(a=>a.role==="partner")) s.accounts.push({role:"partner",email:"fournisseur@travauxcorse.fr",name:"Clim Distribution Corse",password:"fournisseur",partnerId:"partner-demo"});
    s.partnerAssignments ||= [{id:"pa-1",projectId:"dem-1",partnerId:"partner-demo",status:"Demande de prix envoyée",date:date(),clientVisible:false,companyVisible:true}];
    s.priceRequests ||= [{id:"price-1",projectId:"dem-1",partnerId:"partner-demo",product:"Climatisation réversible",description:"Fourniture d’un mono-split silencieux avec accessoires de pose.",quantities:"1 unité intérieure + 1 unité extérieure",deadline:date(),adminComment:"Proposer deux gammes avec délais Corse.",status:"Envoyée"}];
    s.supplierQuotes ||= [];
    s.partnerCategories ||= ["Négoce matériaux","Fournisseur menuiseries","Fournisseur électricité","Fournisseur plomberie","Fournisseur chauffage / climatisation","Fournisseur carrelage","Fournisseur peinture","Fournisseur isolation","Fournisseur toiture","Fournisseur outillage","Bureau d’études","Diagnostiqueur","Architecte","Maître d’œuvre","Courtier en travaux","Fournisseur photovoltaïque","Fournisseur rénovation énergétique","Autre partenaire"];
    s.clientProfiles ||= [{email:"sophie@example.fr",firstName:"Sophie",lastName:"P.",phone:"06 00 00 00 00",commune:"Bastia",type:"Particulier"}];
    s.documents ||= demoDocs;
    s.quotes ||= [{id:"quote-1",projectId:"dem-1",company:"Clima Balagne",amount:"2 480 €",status:"Visible client",date:date()}];
    s.invoices ||= [];
    s.siteReports ||= [{id:"pv-1",projectId:"dem-1",title:"PV de visite technique",status:"Signé",date:date(),author:"TravauxCorse"}];
    s.progressPhotos ||= [{id:"photo-1",projectId:"dem-1",name:"Installation unité extérieure",date:date(),author:"Clima Balagne"}];
    s.messages ||= [{id:"msg-1",projectId:"dem-1",from:"TravauxCorse",to:"sophie@example.fr",body:"Votre dossier a été qualifié. Une entreprise vous a été affectée.",date:date(),read:false}];
    s.notifications ||= [{id:"notif-1",to:"sophie@example.fr",text:"Un devis est disponible pour votre dossier dem-1.",date:date(),read:false}];
  }
  const authShell = body => `<section class="portal-auth"><a class="brand centered" href="#" data-page="home"><span>TRAVAUX</span>CORSE<small>Vos travaux, notre priorité</small></a>${body}</section>`;
  function auth(){return authShell(`<div class="auth-heading"><p class="eyebrow">Votre espace sécurisé</p><h1>Connexion / Inscription</h1><p>Suivez vos projets et échangez avec les professionnels de votre chantier.</p></div><div class="auth-choice"><article><div class="auth-icon">👤</div><h2>Je suis un client</h2><p>Déposez et suivez vos demandes, devis, documents et messages.</p><button class="primary" data-page="signin">Me connecter</button><button class="secondary" data-page="registerClient">Créer mon compte client</button></article><article><div class="auth-icon">🏗️</div><h2>Je suis une entreprise</h2><p>Gérez vos chantiers affectés, documents, devis et assurances.</p><button class="primary" data-page="signin">Me connecter</button><button class="secondary" data-page="registerCompany">Créer mon compte entreprise</button></article><article><div class="auth-icon">📦</div><h2>Partenaire / Fournisseur</h2><p>Répondez aux demandes de prix et gérez catalogues, produits et livraisons.</p><button class="primary" data-page="signin">Me connecter</button><button class="secondary" data-page="registerPartner">Créer mon compte fournisseur</button></article></div>`)}
  function signin(){return authShell(`<div class="auth-form-card"><p class="eyebrow">Accès privé</p><h1>Se connecter</h1><form data-portal-login><label>Email<input type="email" name="email" required autocomplete="email"></label><label>Mot de passe<input type="password" name="password" required autocomplete="current-password"></label><p class="form-error" data-form-error></p><button class="primary">Se connecter</button></form><button class="text-link" data-page="forgot">Mot de passe oublié ?</button><div class="auth-links"><button data-page="registerClient">Compte client</button><button data-page="registerCompany">Compte entreprise</button><button data-page="registerPartner">Compte fournisseur</button></div><p class="demo-note"><strong>Comptes démo :</strong> admin/admin · client/client · artisan/artisan · fournisseur/fournisseur</p></div>`)}
  function forgot(){return authShell(`<div class="auth-form-card"><p class="eyebrow">Réinitialisation</p><h1>Mot de passe oublié</h1><p>Indiquez votre adresse email. En production, un lien sécurisé vous sera envoyé.</p><form data-forgot><label>Email<input type="email" name="email" required></label><button class="primary">Envoyer le lien</button></form><button class="text-link" data-page="signin">Retour à la connexion</button></div>`)}
  function registerClient(){return authShell(`<div class="auth-form-card wide"><p class="eyebrow">Espace client</p><h1>Créer mon compte client</h1><form class="portal-form-grid" data-register-client><label>Prénom<input name="firstName" required></label><label>Nom<input name="lastName" required></label><label>Email<input type="email" name="email" required></label><label>Téléphone<input name="phone" required></label><label>Commune<input name="commune" required></label><label>Type de client<select name="type"><option>Particulier</option><option>Professionnel</option><option>Syndic</option><option>Bailleur</option><option>Collectivité</option></select></label><label class="full">Adresse<input name="address"></label><label>Mot de passe<input type="password" name="password" minlength="8" required></label><label>Confirmation<input type="password" name="confirm" minlength="8" required></label><label class="check full"><input type="checkbox" name="terms" required> J’accepte les conditions générales.</label><label class="check full"><input type="checkbox" name="privacy" required> J’accepte la politique de confidentialité.</label><p class="form-error full" data-form-error></p><button class="primary full">Créer mon compte</button></form></div>`)}
  function registerCompany(s){return authShell(`<div class="auth-form-card wide"><p class="eyebrow">Entreprise partenaire</p><h1>Créer mon compte entreprise</h1><form class="portal-form-grid" data-register-company><label>Entreprise<input name="company" required></label><label>Responsable<input name="manager" required></label><label>Email<input type="email" name="email" required></label><label>Téléphone<input name="phone" required></label><label>Commune<input name="commune" required></label><label>Département<select name="department"><option>Haute-Corse</option><option>Corse-du-Sud</option></select></label><label>Métiers principaux<select name="trades" multiple>${s.artisans.flatMap(a=>a.trades).filter((x,i,a)=>a.indexOf(x)===i).map(x=>`<option>${e(x)}</option>`).join("")}</select></label><label>Zones d’intervention<input name="zones" required></label><label>SIRET<input name="siret"></label><label>Site internet<input name="website"></label><label class="full">Présentation<textarea name="description"></textarea></label><label>Mot de passe<input type="password" name="password" minlength="8" required></label><label>Confirmation<input type="password" name="confirm" minlength="8" required></label><label class="check full"><input type="checkbox" name="terms" required> J’accepte les conditions générales.</label><label class="check full"><input type="checkbox" name="certify" required> Je certifie l’exactitude des informations.</label><p class="form-error full" data-form-error></p><button class="primary full">Envoyer mon inscription</button></form></div>`)}
  function registerPartner(s){return authShell(`<div class="auth-form-card wide"><p class="eyebrow">Réseau TravauxCorse</p><h1>Inscription partenaire / fournisseur</h1><form class="portal-form-grid" data-register-partner><label>Société<input name="company" required></label><label>Responsable<input name="manager" required></label><label>Email<input type="email" name="email" required></label><label>Téléphone<input name="phone" required></label><label>Commune<input name="commune" required></label><label>Département<select name="department"><option>Haute-Corse</option><option>Corse-du-Sud</option></select></label><label>Type de partenaire<select name="type">${s.partnerCategories.map(x=>`<option>${e(x)}</option>`).join("")}</select></label><label>Domaines d’activité<input name="domains" required></label><label class="full">Zones desservies<input name="zones" required></label><label>SIRET<input name="siret"></label><label>Forme juridique<input name="legalForm"></label><label>Site internet<input name="website"></label><label>Marques distribuées<input name="brands"></label><label>Produits / services<input name="products"></label><label>Délais moyens<input name="deliveryDelay"></label><label>Contact commercial<input name="salesContact"></label><label>Contact technique<input name="technicalContact"></label><label class="full">Conditions de livraison<textarea name="deliveryTerms"></textarea></label><label class="full">Description<textarea name="description"></textarea></label><label>Mot de passe<input type="password" name="password" minlength="8" required></label><label>Confirmation<input type="password" name="confirm" minlength="8" required></label><label class="check full"><input type="checkbox" name="terms" required> J’accepte les conditions générales.</label><label class="check full"><input type="checkbox" name="certify" required> Je certifie l’exactitude des informations.</label><p class="form-error full" data-form-error></p><button class="primary full">Envoyer mon inscription partenaire</button></form></div>`)}
  const stat = (n,l) => `<article class="portal-stat"><strong>${e(n)}</strong><span>${e(l)}</span></article>`;
  const badge = x => `<span class="portal-badge ${String(x).toLowerCase().includes("refus")?"bad":""}">${e(x)}</span>`;
  function layout(kind,s,content){const account=s.accounts.find(a=>a.email===s.currentUserEmail);return `<section class="portal"><aside class="portal-sidebar"><div class="portal-user"><span>${e((account?.name||"U")[0])}</span><div><strong>${e(account?.name||"Utilisateur")}</strong><small>${e(s.currentUserEmail)}</small></div></div><nav>${navs[kind].map(n=>`<button class="${s.portalTab===n?"active":""}" data-portal-tab="${e(n)}">${e(n)}</button>`).join("")}</nav><button class="portal-logout" data-logout>Déconnexion</button></aside><div class="portal-main"><div class="portal-top"><div><p class="eyebrow">Espace ${kind==="company"?"entreprise":kind}</p><h1>${e(s.portalTab)}</h1></div><div class="portal-alert">🔔 ${s.notifications.filter(n=>n.to===s.currentUserEmail&&!n.read).length}</div></div>${content}</div></section>`}
  function requestsFor(s,kind){if(kind==="client")return s.requests.filter(r=>r.email===s.currentUserEmail);if(kind==="company"){const a=s.accounts.find(x=>x.email===s.currentUserEmail);return s.requests.filter(r=>r.assignedArtisanId===a?.artisanId||r.assignedArtisan===a?.name)}return s.requests}
  function tableRequests(rs,admin=false){return `<div class="portal-table-wrap"><table><thead><tr><th>Dossier</th><th>Projet</th><th>Commune</th><th>Statut</th><th>Entreprise</th><th></th></tr></thead><tbody>${rs.map(r=>`<tr><td><strong>${e(r.id)}</strong><small>${e(r.date)}</small></td><td>${e(r.title)}</td><td>${e(r.commune)}</td><td>${badge(r.status)}</td><td>${e(r.assignedArtisan||"En attente")}</td><td><button class="small-btn" data-open-project="${e(r.id)}">Voir le dossier</button>${admin?` <button class="small-btn" data-assign="${e(r.id)}">Affecter</button>`:""}</td></tr>`).join("")||`<tr><td colspan="6">Aucun dossier.</td></tr>`}</tbody></table></div>`}
  function project(s,r,kind){const docs=s.documents.filter(d=>d.projectId===r.id&&(kind==="admin"||kind==="company"||d.visibility==="client"));return `<button class="text-link" data-close-project>â† Retour</button><article class="project-detail"><div class="project-title"><div><p class="eyebrow">Dossier ${e(r.id)}</p><h2>${e(r.title)}</h2><p>${e(r.category)} · ${e(r.commune)}</p></div>${badge(r.status)}</div><div class="project-progress"><span style="width:${Math.min(100,(r.timeline?.length||1)*18)}%"></span></div><div class="detail-grid"><section><h3>Description</h3><p>${e(r.description)}</p><h3>Entreprises affectées</h3><p>${e(r.assignedArtisan||"Aucune entreprise affectée")}</p></section><section><h3>Historique</h3>${(r.timeline||[]).map(x=>`<p class="history-item">âœ“ ${e(x)}</p>`).join("")}</section></div><h3>Documents du dossier</h3>${docTable(docs)}<div class="detail-grid"><section><h3>Devis</h3>${s.quotes.filter(q=>q.projectId===r.id).map(q=>`<p>${e(q.company)} · <strong>${e(q.amount)}</strong> ${badge(q.status)}</p>`).join("")||"<p>Aucun devis.</p>"}</section><section><h3>PV de chantier</h3>${s.siteReports.filter(p=>p.projectId===r.id).map(p=>`<p>${e(p.title)} ${badge(p.status)}</p>`).join("")||"<p>Aucun PV.</p>"}</section></div></article>`}
  function docTable(ds){return `<div class="portal-table-wrap"><table><thead><tr><th>Document</th><th>Type</th><th>Ajouté par</th><th>Date</th><th>Statut</th></tr></thead><tbody>${ds.map(d=>`<tr><td>${e(d.name)}</td><td>${e(d.type)}</td><td>${e(d.owner)}</td><td>${e(d.date)}</td><td>${badge(d.status)}</td></tr>`).join("")||`<tr><td colspan="5">Aucun document.</td></tr>`}</tbody></table></div>`}
  function uploadForm(kind){return `<form class="inline-upload" data-upload="${kind}"><select name="type"><option>${kind}</option><option>Devis</option><option>Facture</option><option>PV de chantier</option><option>Photo d’avancement</option><option>Assurance décennale</option><option>Qualification</option></select><select name="projectId"><option value="dem-1">dem-1</option><option value="dem-2">dem-2</option></select><input name="name" placeholder="Nom du document" required><input type="file" name="file"><button class="primary">Déposer</button></form>`}
  function client(s){if(s.role!=="client"&&s.role!=="admin")return signin();const rs=requestsFor(s,"client"),tab=s.portalTab;if(s.openProject){const r=rs.find(x=>x.id===s.openProject);if(r)return layout("client",s,project(s,r,"client"))}let c="";if(tab==="Tableau de bord")c=`<div class="portal-stats">${stat(rs.filter(r=>!r.status.includes("Clôt")).length,"Demandes en cours")}${stat(rs.filter(r=>r.assignedArtisan).length,"Entreprises affectées")}${stat(s.quotes.filter(q=>rs.some(r=>r.id===q.projectId)&&q.status==="Visible client").length,"Devis reçus")}${stat(s.documents.filter(d=>rs.some(r=>r.id===d.projectId)&&d.visibility==="client").length,"Documents")}${stat(s.messages.filter(m=>m.to===s.currentUserEmail&&!m.read).length,"Messages non lus")}</div><div class="portal-card"><h2>Mes dossiers récents</h2>${tableRequests(rs)}</div>`;else if(tab==="Mes demandes")c=tableRequests(rs);else if(tab==="Nouveau dossier travaux")c=`<div class="portal-card"><h2>Créer un nouveau dossier</h2><p>Décrivez votre besoin grâce au formulaire guidé TravauxCorse.</p><button class="primary" data-page="request">Déposer une demande</button></div>`;else if(tab==="Documents")c=`<div class="portal-card"><h2>Mes documents</h2>${uploadForm("Document")}${docTable(s.documents.filter(d=>rs.some(r=>r.id===d.projectId)&&d.visibility==="client"))}</div>`;else if(tab==="Messages")c=messages(s);else c=genericTab(s,tab,rs,"client");return layout("client",s,c)}
  function company(s){if(s.role!=="artisan"&&s.role!=="admin")return signin();const rs=requestsFor(s,"company"),tab=s.portalTab,profile=s.companyProfiles.find(p=>p.email===s.currentUserEmail);if(s.openProject){const r=rs.find(x=>x.id===s.openProject);if(r)return layout("company",s,project(s,r,"company"))}let c="";if(tab==="Tableau de bord")c=`${profile?.status!=="Validée"?`<div class="portal-warning">Votre profil est en attente de validation par TravauxCorse. Certaines fonctions restent limitées.</div>`:""}<div class="portal-stats">${stat(rs.length,"Chantiers affectés")}${stat(s.quotes.filter(q=>q.company===profile?.company).length,"Devis envoyés")}${stat(s.invoices.length,"Factures déposées")}${stat(s.messages.filter(m=>m.to===s.currentUserEmail&&!m.read).length,"Messages non lus")}</div><div class="portal-card"><h2>Chantiers affectés</h2>${tableRequests(rs)}</div>`;else if(tab==="Chantiers affectés")c=tableRequests(rs);else if(tab==="Mes assurances")c=`<div class="portal-card"><h2>Assurance décennale</h2>${!profile?.insuranceEnd?`<div class="portal-warning">Votre assurance décennale n’est pas renseignée ou n’est plus valide. Merci de mettre à jour votre document.</div>`:""}<form class="portal-form-grid" data-insurance><label>Assureur<input name="insurer"></label><label>N° de contrat<input name="contract"></label><label>Date de début<input type="date" name="start"></label><label>Date de fin<input type="date" name="end"></label><label class="full">Métiers couverts<input name="covered"></label><label class="full">Justificatif<input type="file" name="file"></label><button class="primary full">Enregistrer</button></form></div>`;else if(["Mes documents","Mes devis","Mes factures","Mes qualifications","Photos d’avancement","PV de chantier"].includes(tab))c=`<div class="portal-card"><h2>${e(tab)}</h2>${uploadForm(tab)}${docTable(s.documents.filter(d=>d.owner===profile?.company||d.owner===s.currentUserEmail))}</div>`;else if(tab==="Messages")c=messages(s);else c=genericTab(s,tab,rs,"company");return layout("company",s,c)}
  function messages(s){return `<div class="portal-card"><h2>Messagerie dossiers</h2><div class="message-list">${s.messages.filter(m=>m.to===s.currentUserEmail||m.from===s.currentUserEmail||s.role==="admin").map(m=>`<article><strong>${e(m.from)}</strong><small>${e(m.date)} · ${e(m.projectId)}</small><p>${e(m.body)}</p></article>`).join("")}</div><form class="message-form" data-message><select name="projectId">${s.requests.map(r=>`<option>${e(r.id)}</option>`).join("")}</select><input name="to" placeholder="Destinataire" required><textarea name="body" placeholder="Votre message" required></textarea><button class="primary">Envoyer</button></form></div>`}
  function partner(s){if(s.role!=="partner"&&s.role!=="admin")return signin();const account=s.accounts.find(a=>a.email===s.currentUserEmail),profile=s.partnerProfiles.find(p=>p.id===account?.partnerId||p.email===s.currentUserEmail),assignments=s.partnerAssignments.filter(a=>s.role==="admin"||a.partnerId===profile?.id),rs=s.requests.filter(r=>assignments.some(a=>a.projectId===r.id)),tab=s.portalTab;if(s.openProject){const r=rs.find(x=>x.id===s.openProject);if(r)return layout("partner",s,project(s,r,"partner"))}let c="";if(tab==="Tableau de bord")c=`${profile?.status!=="Validé"?`<div class="portal-warning">Votre inscription partenaire a bien été enregistrée. Votre profil sera vérifié par l’équipe TravauxCorse avant activation complète.</div>`:""}<div class="portal-stats">${stat(rs.length,"Dossiers affectés")}${stat(s.priceRequests.filter(p=>p.partnerId===profile?.id&&!p.status.includes("Clôt")).length,"Demandes de prix")}${stat(s.supplierQuotes.filter(q=>q.partnerId===profile?.id).length,"Devis envoyés")}${stat(s.documents.filter(d=>d.partnerId===profile?.id&&d.status==="En attente").length,"Documents à vérifier")}${stat(s.messages.filter(m=>m.to===s.currentUserEmail&&!m.read).length,"Messages non lus")}</div><div class="portal-card"><h2>Dossiers récemment affectés</h2>${tableRequests(rs)}</div>`;else if(tab==="Dossiers affectés")c=tableRequests(rs);else if(tab==="Demandes de prix")c=`<div class="portal-card"><h2>Demandes de prix</h2>${s.priceRequests.filter(p=>p.partnerId===profile?.id).map(p=>`<article class="price-card"><div><strong>${e(p.product)}</strong><small>Dossier ${e(p.projectId)} · réponse avant le ${e(p.deadline)}</small></div>${badge(p.status)}<p>${e(p.description)}</p><p><strong>Quantités :</strong> ${e(p.quantities||"Non précisées")}</p><p class="muted">${e(p.adminComment)}</p><button class="small-btn" data-prepare-quote="${e(p.id)}">Préparer un devis</button><button class="small-btn" data-refuse-price="${e(p.id)}">Refuser</button></article>`).join("")||"<p>Aucune demande de prix.</p>"}</div>`;else if(tab==="Mes devis fournisseurs")c=`<div class="portal-card"><h2>Mes devis fournisseurs</h2><form class="portal-form-grid" data-supplier-quote><label>Dossier<select name="projectId">${rs.map(r=>`<option>${e(r.id)}</option>`).join("")}</select></label><label>Demande de prix<select name="priceRequestId">${s.priceRequests.filter(p=>p.partnerId===profile?.id).map(p=>`<option value="${e(p.id)}">${e(p.product)}</option>`).join("")}</select></label><label class="full">Titre<input name="title" required></label><label>Montant HT<input name="amountHT" required></label><label>TVA<input name="vat" value="20 %"></label><label>Montant TTC<input name="amountTTC" required></label><label>Délai de livraison<input name="deliveryDelay" required></label><label>Validité<input type="date" name="validUntil"></label><label class="full">PDF<input type="file" name="file"></label><label class="full">Commentaire<textarea name="comment"></textarea></label><button class="primary full">Déposer le devis fournisseur</button></form>${supplierQuoteTable(s.supplierQuotes.filter(q=>q.partnerId===profile?.id))}</div>`;else if(["Mes documents","Catalogues et fiches techniques"].includes(tab))c=`<div class="portal-card"><h2>${e(tab)}</h2>${partnerUploadForm()}${docTable(s.documents.filter(d=>d.partnerId===profile?.id))}</div>`;else if(tab==="Marques et produits")c=`<div class="portal-card"><h2>Marques et produits</h2><form class="portal-form-grid" data-partner-products><label class="full">Marques distribuées<input name="brands" value="${e(profile?.brands)}"></label><label class="full">Familles et produits<input name="products" value="${e(profile?.products)}"></label><label>Délais moyens<input name="deliveryDelay" value="${e(profile?.deliveryDelay)}"></label><label>Zones de livraison<input name="zones" value="${e(profile?.zones)}"></label><label class="full">Conditions de livraison<textarea name="deliveryTerms">${e(profile?.deliveryTerms)}</textarea></label><button class="primary full">Enregistrer</button></form></div>`;else if(tab==="Messages")c=messages(s);else if(tab==="Ma fiche partenaire")c=`<div class="portal-card"><h2>${e(profile?.company)}</h2><p>${badge(profile?.status)}</p><p><strong>Type :</strong> ${e(profile?.type)}</p><p><strong>Domaines :</strong> ${e(profile?.domains)}</p><p><strong>Zone :</strong> ${e(profile?.zones)}</p><p>Cette fiche reste non publique tant que l’administration ne l’a pas validée et publiée.</p></div>`;else c=genericTab(s,tab,rs,"partner");return layout("partner",s,c)}
  function partnerUploadForm(){return `<form class="inline-upload" data-partner-upload><select name="type"><option>Catalogue</option><option>Fiche technique</option><option>Fiche produit</option><option>Assurance RC professionnelle</option><option>Extrait Kbis</option><option>Certification</option><option>Garantie fabricant</option><option>Notice</option></select><input name="name" placeholder="Nom du document" required><input type="date" name="validUntil"><select name="visibility"><option value="administration">Administration uniquement</option><option value="company">Entreprises affectées</option><option value="client">Client si autorisé</option><option value="public">Public si autorisé</option></select><input type="file" name="file"><button class="primary">Déposer</button></form>`}
  function supplierQuoteTable(qs){return `<div class="portal-table-wrap"><table><thead><tr><th>Devis</th><th>Dossier</th><th>Montant TTC</th><th>Livraison</th><th>Statut</th></tr></thead><tbody>${qs.map(q=>`<tr><td>${e(q.title)}</td><td>${e(q.projectId)}</td><td>${e(q.amountTTC)}</td><td>${e(q.deliveryDelay)}</td><td>${badge(q.status)}</td></tr>`).join("")||`<tr><td colspan="5">Aucun devis fournisseur.</td></tr>`}</tbody></table></div>`}
  function genericTab(s,tab,rs,kind){if(tab.includes("entreprise")||tab.includes("affectée"))return `<div class="portal-card"><h2>${e(tab)}</h2>${rs.filter(r=>r.assignedArtisan).map(r=>`<article class="list-card"><strong>${e(r.assignedArtisan)}</strong><span>${e(r.title)} · ${e(r.commune)}</span></article>`).join("")||"<p>Aucune donnée disponible.</p>"}</div>`;if(tab.includes("Suivi"))return `<div class="portal-card"><h2>Suivi de chantier</h2>${rs.map(r=>`<article class="list-card"><strong>${e(r.title)}</strong><div class="project-progress"><span style="width:${Math.min(100,(r.timeline?.length||1)*18)}%"></span></div><small>Dernière étape : ${e((r.timeline||[]).slice(-1)[0])}</small></article>`).join("")}</div>`;return `<div class="portal-card"><h2>${e(tab)}</h2><p>Cette rubrique est prête à recevoir les informations liées à votre compte et à vos dossiers.</p></div>`}
  function adminPartnerTab(s,tab){if(tab==="Partenaires / Fournisseurs")return `<div class="portal-card"><h2>Partenaires / Fournisseurs</h2><div class="portal-table-wrap"><table><thead><tr><th>Société</th><th>Type</th><th>Responsable</th><th>Zone</th><th>Statut</th><th>Actions</th></tr></thead><tbody>${s.partnerProfiles.map(p=>`<tr><td><strong>${e(p.company)}</strong><small>${e(p.email)} · ${e(p.phone)}</small></td><td>${e(p.type)}</td><td>${e(p.manager)}</td><td>${e(p.zones)}</td><td>${badge(p.status)}</td><td><button class="small-btn" data-partner-status="${e(p.id)}">${p.status==="Validé"?"Suspendre":"Valider"}</button> <button class="small-btn" data-partner-assign="${e(p.id)}">Affecter</button></td></tr>`).join("")}</tbody></table></div></div>`;if(tab==="Demandes de prix fournisseurs")return `<div class="portal-card"><h2>Demandes de prix fournisseurs</h2><form class="portal-form-grid" data-admin-price-request><label>Dossier<select name="projectId">${s.requests.map(r=>`<option value="${e(r.id)}">${e(r.id)} · ${e(r.title)}</option>`).join("")}</select></label><label>Partenaire<select name="partnerId">${s.partnerProfiles.filter(p=>p.status==="Validé").map(p=>`<option value="${e(p.id)}">${e(p.company)}</option>`).join("")}</select></label><label>Produit / prestation<input name="product" required></label><label>Quantités<input name="quantities"></label><label class="full">Description<textarea name="description" required></textarea></label><label>Date limite<input type="date" name="deadline" required></label><label>Commentaire admin<input name="adminComment"></label><button class="primary full">Envoyer la demande de prix</button></form>${supplierQuoteTable(s.supplierQuotes)}</div>`;return ""}  function admin(s){if(s.role!=="admin")return signin();const tab=s.portalTab;if(s.openProject){const r=s.requests.find(x=>x.id===s.openProject);if(r)return layout("admin",s,project(s,r,"admin"))}let c=tab==="Éditeur du site"?fullSiteEditor(s):adminPartnerTab(s,tab);if(c){}else if(tab==="Tableau de bord")c=`<div class="portal-stats">${stat(s.requests.length,"Demandes")}${stat(s.requests.filter(r=>!r.assignedArtisan).length,"À affecter")}${stat(s.companyProfiles.filter(p=>p.status!=="Validée").length,"Entreprises à valider")}${stat(s.documents.filter(d=>d.status==="En attente").length,"Documents à vérifier")}${stat(s.quotes.length,"Devis")}${stat(s.messages.filter(m=>!m.read).length,"Messages non lus")}</div><div class="portal-card"><h2>Demandes récentes</h2>${tableRequests(s.requests,true)}</div>`;else if(["Demandes clients","Dossiers travaux","Affectations entreprises"].includes(tab))c=`<div class="portal-card"><h2>${e(tab)}</h2>${tableRequests(s.requests,true)}</div>`;else if(tab==="Entreprises")c=`<div class="portal-card"><h2>Validation des entreprises</h2>${s.companyProfiles.map(p=>`<article class="company-row"><div><strong>${e(p.company)}</strong><span>${e(p.trades)} · ${e(p.commune)}</span></div>${badge(p.status)}<button class="small-btn" data-company-status="${e(p.id)}">${p.status==="Validée"?"Suspendre":"Valider"}</button></article>`).join("")}</div>`;else if(tab==="Documents")c=`<div class="portal-card"><h2>Centre documentaire</h2>${docTable(s.documents)}<div class="admin-doc-actions"><p>Les documents sensibles restent privés tant qu’ils ne sont pas validés.</p></div></div>`;else if(tab==="Messages")c=messages(s);else if(tab==="Clients")c=`<div class="portal-card"><h2>Clients</h2>${s.clientProfiles.map(p=>`<article class="company-row"><div><strong>${e(p.firstName)} ${e(p.lastName)}</strong><span>${e(p.email)} · ${e(p.commune)}</span></div>${badge(p.type)}</article>`).join("")}</div>`;else c=genericTab(s,tab,s.requests,"admin");return layout("admin",s,c)}
  function publicPartnerEditor(s){return `<div class="portal-card content-editor"><div class="editor-heading"><div><p class="eyebrow">Modification sans code</p><h2>Partenaires affichés sur le site</h2><p>Modifiez les champs puis cliquez sur Enregistrer. Une fiche peut être masquée sans être supprimée.</p></div><button class="primary" data-add-public-partner>+ Ajouter un partenaire</button></div><div class="editor-list">${s.supplierPartners.map((p,index)=>`<form class="editor-partner-card" data-edit-public-partner="${e(p.id)}"><div class="editor-card-head"><strong>${e(p.name||"Nouveau partenaire")}</strong><span>Position ${index+1}</span></div><div class="portal-form-grid"><label>Nom public<input name="name" value="${e(p.name)}" required></label><label>Catégorie<input name="family" value="${e(p.family)}" required></label><label>Zone couverte<input name="zone" value="${e(p.zone)}"></label><label>Badge<input name="badge" value="${e(p.badge)}"></label><label class="full">Présentation<textarea name="text">${e(p.text)}</textarea></label><label class="full">Points forts, séparés par des virgules<input name="benefits" value="${e((p.benefits||[]).join(", "))}"></label><label>Ordre d’affichage<input type="number" min="0" name="order" value="${p.order??index}"></label><label class="check"><input type="checkbox" name="hidden" ${p.hidden?"checked":""}> Masquer du site public</label></div><div class="editor-actions"><button class="primary" type="submit">Enregistrer</button><button class="small-btn" type="button" data-move-public="up" data-id="${e(p.id)}">Monter</button><button class="small-btn" type="button" data-move-public="down" data-id="${e(p.id)}">Descendre</button><button class="danger-btn" type="button" data-delete-public-partner="${e(p.id)}">Supprimer</button></div></form>`).join("")}</div><div class="editor-help"><strong>Publication</strong><p>Les fiches non masquées apparaissent automatiquement dans « Nos partenaires ». Les modifications sont enregistrées dans le navigateur pour cette version.</p></div></div>`}
  function fullSiteEditor(s){const settings=s.siteSettings;return `<div class="cms-intro"><p class="eyebrow">Gestion complète sans code</p><h2>Éditeur du site</h2><p>Modifiez les contenus publics depuis les blocs ci-dessous. Chaque bloc possède son propre bouton d’enregistrement.</p></div><details class="cms-section" open><summary>Identité, accueil et coordonnées</summary><form class="portal-form-grid cms-body" data-cms-settings><label>Nom — première ligne<input name="brandTop" value="${e(settings.brandTop)}"></label><label>Nom — deuxième ligne<input name="brandBottom" value="${e(settings.brandBottom)}"></label><label class="full">Slogan<input name="tagline" value="${e(settings.tagline)}"></label><label class="full">Grand titre d’accueil<input name="headline" value="${e(settings.headline)}"></label><label class="full">Introduction<textarea name="intro">${e(settings.intro)}</textarea></label><label>Email public<input type="email" name="contactEmail" value="${e(settings.contactEmail)}"></label><label>Téléphone public<input name="contactPhone" value="${e(settings.contactPhone)}"></label><label class="full">Texte du pied de page<textarea name="footerText">${e(settings.footerText)}</textarea></label><label>Nombre entreprises<input name="statCompanies" value="${e(settings.statCompanies)}"></label><label>Demandes traitées<input name="statRequests" value="${e(settings.statRequests)}"></label><label>Départements couverts<input name="statDepartments" value="${e(settings.statDepartments)}"></label><label>Catégories affichées<input name="statCategories" value="${e(settings.statCategories)}"></label><button class="primary full">Enregistrer l’identité et l’accueil</button></form></details><details class="cms-section"><summary>Catégories de travaux</summary><form class="cms-body" data-cms-trades><p>Une catégorie par ligne. Leur ordre détermine l’ordre sur la page d’accueil et dans les formulaires.</p><textarea name="trades" rows="14">${e((s.customTrades||[]).join("\n"))}</textarea><button class="primary">Enregistrer les catégories</button></form></details><details class="cms-section"><summary>Annuaire des entreprises</summary><div class="cms-body"><button class="primary" data-add-public-artisan>+ Ajouter une entreprise</button><div class="editor-list">${s.artisans.map(a=>`<form class="editor-partner-card" data-edit-public-artisan="${e(a.id)}"><div class="editor-card-head"><strong>${e(a.name)}</strong>${badge(a.verified?"Visible et vérifiée":"Masquée / à vérifier")}</div><div class="portal-form-grid"><label>Nom<input name="name" value="${e(a.name)}" required></label><label>Ville<input name="city" value="${e(a.city)}"></label><label>Département<input name="department" value="${e(a.department)}"></label><label>Statut<input name="status" value="${e(a.status)}"></label><label class="full">Métiers, séparés par des virgules<input name="trades" value="${e((a.trades||[]).join(", "))}"></label><label class="full">Spécialités énergie<input name="energy" value="${e((a.energy||[]).join(", "))}"></label><label class="full">Présentation<textarea name="text">${e(a.text)}</textarea></label><label class="check"><input type="checkbox" name="verified" ${a.verified?"checked":""}> Afficher comme vérifiée</label><label class="check"><input type="checkbox" name="premium" ${a.premium?"checked":""}> Mise en avant Premium</label></div><div class="editor-actions"><button class="primary">Enregistrer</button><button type="button" class="danger-btn" data-delete-public-artisan="${e(a.id)}">Supprimer</button></div></form>`).join("")}</div></div></details><details class="cms-section"><summary>Partenaires publics</summary><div class="cms-nested">${publicPartnerEditor(s)}</div></details><details class="cms-section"><summary>Sauvegarde et restauration</summary><div class="cms-body"><p>Exportez régulièrement le contenu avant une modification importante.</p><div class="editor-actions"><button class="primary" data-export-site>Exporter la sauvegarde</button><label class="small-btn import-label">Importer une sauvegarde<input type="file" accept="application/json" data-import-site hidden></label></div><textarea data-export-output readonly placeholder="La sauvegarde JSON apparaîtra ici."></textarea></div></details>`}
  function render(page,s){ensure(s);return ({auth,signin,registerClient:()=>registerClient(s),registerCompany:()=>registerCompany(s),registerPartner:()=>registerPartner(s),forgot,client:()=>client(s),company:()=>company(s),partner:()=>partner(s),admin:()=>admin(s)}[page]||auth)()}
  function bind(s,api){
    document.querySelectorAll("[data-portal-tab]").forEach(b=>b.onclick=()=>{s.portalTab=b.dataset.portalTab;s.openProject="";api.saveState();api.render()});
    document.querySelectorAll("[data-open-project]").forEach(b=>b.onclick=()=>{s.openProject=b.dataset.openProject;api.saveState();api.render()});
    document.querySelector("[data-close-project]")?.addEventListener("click",()=>{s.openProject="";api.saveState();api.render()});
    document.querySelector("[data-portal-login]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget)),a=s.accounts.find(x=>x.email.toLowerCase()===d.email.toLowerCase()&&x.password===d.password);if(!a){ev.currentTarget.querySelector("[data-form-error]").textContent="Email ou mot de passe incorrect.";return}s.role=a.role;s.currentUserEmail=a.email;s.portalTab="Tableau de bord";s.page=a.role==="admin"?"admin":a.role==="artisan"?"artisanSpace":a.role==="partner"?"partnerSpace":a.role==="client"?"client":"auth";api.saveState();api.render()});
    document.querySelector("[data-register-client]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget)),err=ev.currentTarget.querySelector("[data-form-error]");if(d.password!==d.confirm){err.textContent="Les mots de passe ne correspondent pas.";return}if(s.accounts.some(a=>a.email===d.email)){err.textContent="Cette adresse email est déjà utilisée.";return}s.accounts.push({role:"client",email:d.email,name:`${d.firstName} ${d.lastName}`,password:d.password});s.clientProfiles.push({...d});s.role="client";s.currentUserEmail=d.email;s.portalTab="Tableau de bord";s.page="client";s.notifications.push({id:id("notif"),to:d.email,text:"Bienvenue sur TravauxCorse. Vous pouvez déposer votre première demande.",date:date(),read:false});api.saveState();api.render()});
    document.querySelector("[data-register-company]")?.addEventListener("submit",ev=>{ev.preventDefault();const fd=new FormData(ev.currentTarget),d=Object.fromEntries(fd),err=ev.currentTarget.querySelector("[data-form-error]");if(d.password!==d.confirm){err.textContent="Les mots de passe ne correspondent pas.";return}if(s.accounts.some(a=>a.email===d.email)){err.textContent="Cette adresse email est déjà utilisée.";return}const pid=id("company");s.accounts.push({role:"artisan",email:d.email,name:d.company,password:d.password,artisanId:pid});s.companyProfiles.push({id:pid,...d,status:"En attente de validation",public:false});s.role="artisan";s.currentUserEmail=d.email;s.portalTab="Tableau de bord";s.page="artisanSpace";s.notifications.push({id:id("notif"),to:"admin@travauxcorse.fr",text:`Nouvelle inscription entreprise : ${d.company}`,date:date(),read:false});api.saveState();api.render()});
    document.querySelector("[data-register-partner]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget)),err=ev.currentTarget.querySelector("[data-form-error]");if(d.password!==d.confirm){err.textContent="Les mots de passe ne correspondent pas.";return}if(s.accounts.some(a=>a.email===d.email)){err.textContent="Cette adresse email est déjà utilisée.";return}const pid=id("partner");s.accounts.push({role:"partner",email:d.email,name:d.company,password:d.password,partnerId:pid});s.partnerProfiles.push({id:pid,...d,status:"En attente de validation",subscription:"Gratuit",public:false,date:date()});s.role="partner";s.currentUserEmail=d.email;s.portalTab="Tableau de bord";s.page="partnerSpace";s.notifications.push({id:id("notif"),to:"admin@travauxcorse.fr",text:`Nouveau partenaire inscrit : ${d.company}`,date:date(),read:false});api.saveState();api.render()});
    document.querySelector("[data-partner-upload]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget)),a=s.accounts.find(x=>x.email===s.currentUserEmail);s.documents.unshift({id:id("pdoc"),partnerId:a.partnerId,projectId:"profil-partenaire",name:d.name,type:d.type,owner:a.name,status:"En attente",visibility:d.visibility,validUntil:d.validUntil,date:date()});s.notifications.push({id:id("notif"),to:"admin@travauxcorse.fr",text:`Nouveau document fournisseur : ${d.name}`,date:date(),read:false});api.saveState();api.render()});
    document.querySelector("[data-supplier-quote]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget)),a=s.accounts.find(x=>x.email===s.currentUserEmail);s.supplierQuotes.unshift({id:id("sq"),partnerId:a.partnerId,...d,status:"En analyse admin",clientVisible:false,companyVisible:false,date:date()});const p=s.priceRequests.find(x=>x.id===d.priceRequestId);if(p)p.status="Devis fournisseur envoyé";s.notifications.push({id:id("notif"),to:"admin@travauxcorse.fr",text:`Nouveau devis fournisseur pour ${d.projectId}`,date:date(),read:false});api.saveState();api.render()});
    document.querySelector("[data-partner-products]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget)),a=s.accounts.find(x=>x.email===s.currentUserEmail),p=s.partnerProfiles.find(x=>x.id===a.partnerId);Object.assign(p,d);api.saveState();api.render()});
    document.querySelectorAll("[data-refuse-price]").forEach(b=>b.onclick=()=>{const p=s.priceRequests.find(x=>x.id===b.dataset.refusePrice);p.status="Refusée";api.saveState();api.render()});
    document.querySelector("[data-forgot]")?.addEventListener("submit",ev=>{ev.preventDefault();ev.currentTarget.innerHTML='<div class="success-box">Si un compte correspond à cette adresse, un lien de réinitialisation sera envoyé.</div>'});
    document.querySelectorAll("[data-upload]").forEach(f=>f.onsubmit=ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(f));s.documents.unshift({id:id("doc"),projectId:d.projectId,name:d.name,type:d.type,owner:s.accounts.find(a=>a.email===s.currentUserEmail)?.name||s.currentUserEmail,status:"En attente",visibility:s.role==="client"?"client":"administration",date:date()});api.saveState();api.render()});
    document.querySelector("[data-message]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget));s.messages.unshift({id:id("msg"),...d,from:s.currentUserEmail,date:date(),read:false});api.saveState();api.render()});
    document.querySelectorAll("[data-company-status]").forEach(b=>b.onclick=()=>{const p=s.companyProfiles.find(x=>x.id===b.dataset.companyStatus);p.status=p.status==="Validée"?"Suspendue":"Validée";api.saveState();api.render()});
    document.querySelectorAll("[data-partner-status]").forEach(b=>b.onclick=()=>{const p=s.partnerProfiles.find(x=>x.id===b.dataset.partnerStatus);p.status=p.status==="Validé"?"Suspendu":"Validé";api.saveState();api.render()});
    document.querySelector("[data-add-public-partner]")?.addEventListener("click",()=>{s.supplierPartners.unshift({id:id("sup"),name:"Nouveau partenaire",family:"Catégorie",zone:"Toute la Corse",badge:"Partenaire",text:"Présentez ici les produits ou services proposés.",benefits:["Service local"],order:0,hidden:true});s.supplierPartners.forEach((p,i)=>p.order=i);api.saveState();api.render()});
    document.querySelector("[data-cms-settings]")?.addEventListener("submit",ev=>{ev.preventDefault();Object.assign(s.siteSettings,Object.fromEntries(new FormData(ev.currentTarget)));api.saveState();api.render()});
    document.querySelector("[data-cms-trades]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget));s.customTrades=String(d.trades||"").split(/\r?\n/).map(x=>x.trim()).filter(Boolean);s.siteSettings.statCategories=String(s.customTrades.length);api.saveState();api.render()});
    document.querySelector("[data-add-public-artisan]")?.addEventListener("click",()=>{s.artisans.unshift({id:id("art"),name:"Nouvelle entreprise",city:"",department:"Haute-Corse",trades:[],energy:[],rating:0,reviews:0,status:"À compléter",verified:false,premium:false,urgent:false,insurance:false,photos:false,text:""});api.saveState();api.render()});
    document.querySelectorAll("[data-edit-public-artisan]").forEach(form=>form.addEventListener("submit",ev=>{ev.preventDefault();const a=s.artisans.find(x=>x.id===form.dataset.editPublicArtisan),d=Object.fromEntries(new FormData(form));Object.assign(a,d,{trades:String(d.trades||"").split(",").map(x=>x.trim()).filter(Boolean),energy:String(d.energy||"").split(",").map(x=>x.trim()).filter(Boolean),verified:form.elements.verified.checked,premium:form.elements.premium.checked});api.saveState();api.render()}));
    document.querySelectorAll("[data-delete-public-artisan]").forEach(b=>b.onclick=()=>{if(!confirm("Supprimer cette entreprise de l’annuaire public ?"))return;s.artisans=s.artisans.filter(x=>x.id!==b.dataset.deletePublicArtisan);api.saveState();api.render()});
    document.querySelector("[data-export-site]")?.addEventListener("click",()=>{const json=JSON.stringify(s,null,2),out=document.querySelector("[data-export-output]");out.value=json;const blob=new Blob([json],{type:"application/json"}),url=URL.createObjectURL(blob),link=document.createElement("a");link.href=url;link.download=`travauxcorse-sauvegarde-${date()}.json`;link.click();setTimeout(()=>URL.revokeObjectURL(url),1000)});
    document.querySelector("[data-import-site]")?.addEventListener("change",async ev=>{const file=ev.currentTarget.files[0];if(!file)return;try{const restored=JSON.parse(await file.text());Object.assign(s,restored,{role:"admin",currentUserEmail:s.currentUserEmail,page:"admin",portalTab:"Éditeur du site"});api.saveState();api.render()}catch{alert("Cette sauvegarde n’est pas un fichier TravauxCorse valide.")}});
    document.querySelectorAll("[data-edit-public-partner]").forEach(form=>form.addEventListener("submit",ev=>{ev.preventDefault();const p=s.supplierPartners.find(x=>x.id===form.dataset.editPublicPartner),d=Object.fromEntries(new FormData(form));Object.assign(p,d,{order:Number(d.order)||0,hidden:form.elements.hidden.checked,benefits:String(d.benefits||"").split(",").map(x=>x.trim()).filter(Boolean)});s.supplierPartners.sort((a,b)=>(a.order||0)-(b.order||0));s.supplierPartners.forEach((x,i)=>x.order=i);api.saveState();api.render()}));
    document.querySelectorAll("[data-move-public]").forEach(b=>b.onclick=()=>{const sorted=[...s.supplierPartners].sort((a,c)=>(a.order||0)-(c.order||0)),from=sorted.findIndex(x=>x.id===b.dataset.id),to=b.dataset.movePublic==="up"?from-1:from+1;if(from<0||to<0||to>=sorted.length)return;[sorted[from],sorted[to]]=[sorted[to],sorted[from]];sorted.forEach((x,i)=>x.order=i);s.supplierPartners=sorted;api.saveState();api.render()});
    document.querySelectorAll("[data-delete-public-partner]").forEach(b=>b.onclick=()=>{if(!confirm("Supprimer définitivement ce partenaire de la liste publique ?"))return;s.supplierPartners=s.supplierPartners.filter(x=>x.id!==b.dataset.deletePublicPartner);s.supplierPartners.forEach((x,i)=>x.order=i);api.saveState();api.render()});
    document.querySelectorAll("[data-partner-assign]").forEach(b=>b.onclick=()=>{const project=s.requests[0],partnerId=b.dataset.partnerAssign;if(!s.partnerAssignments.some(a=>a.projectId===project.id&&a.partnerId===partnerId))s.partnerAssignments.push({id:id("pa"),projectId:project.id,partnerId,status:"Affecté",date:date(),clientVisible:false,companyVisible:false});api.saveState();api.render()});
    document.querySelector("[data-admin-price-request]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget));s.priceRequests.unshift({id:id("price"),...d,status:"Envoyée"});if(!s.partnerAssignments.some(a=>a.projectId===d.projectId&&a.partnerId===d.partnerId))s.partnerAssignments.push({id:id("pa"),projectId:d.projectId,partnerId:d.partnerId,status:"Demande de prix envoyée",date:date(),clientVisible:false,companyVisible:false});const p=s.partnerProfiles.find(x=>x.id===d.partnerId);s.notifications.push({id:id("notif"),to:p.email,text:`Nouvelle demande de prix pour le dossier ${d.projectId}`,date:date(),read:false});api.saveState();api.render()});
    document.querySelectorAll("[data-assign]").forEach(b=>b.onclick=()=>{const r=s.requests.find(x=>x.id===b.dataset.assign),a=s.artisans.find(x=>x.verified)||s.artisans[0];r.assignedArtisanId=a.id;r.assignedArtisan=a.name;r.status="Entreprises affectées";r.timeline=[...(r.timeline||[]),"Entreprise affectée"];api.saveState();api.render()});
    document.querySelector("[data-insurance]")?.addEventListener("submit",ev=>{ev.preventDefault();const d=Object.fromEntries(new FormData(ev.currentTarget)),p=s.companyProfiles.find(x=>x.email===s.currentUserEmail);Object.assign(p,{insurer:d.insurer,insuranceEnd:d.end});s.documents.unshift({id:id("doc"),projectId:"profil",name:"Assurance décennale",type:"Assurance décennale",owner:p.company,status:"En attente",visibility:"administration",date:date()});api.saveState();api.render()});
  }
  window.TravauxCorsePortal={ensure,render,bind};
})();
